void chars_initialize(char *a, int n, char m)
/*@ Require 0 <= n && n < INT_MAX && CharArray::undef_full(a, n)
    Ensure CharArray::full(a, n, repeat_Z(m, n))
*/
{
  int i;
  /*@ Inv Assert
      0 <= i && i <= n@pre &&
      0 <= n@pre && n@pre < INT_MAX &&
      a == a@pre && m == m@pre && n == n@pre &&
      CharArray::full(a@pre, i, repeat_Z(m@pre, i)) *
      CharArray::undef_seg(a@pre, i, n@pre)
  */
  for (i = 0; i < n; i++)
  {
    a[i] = m;
  }
}

/*@ Extern Coq (IsMajorityElement : Z -> list Z -> Prop) */
/*@ Extern Coq (MajorityOnReduced : Z -> Z -> Z -> list Z -> Prop) */

/*@ Import Coq Require Import SimpleC.EE.QCP_demos_LLM.majorityElement_lib */

int majorityElement(int* nums, int numsSize)
/*@ With (l : list Z)
    Require exists x, IsMajorityElement(x,l) && 1 <= numsSize && numsSize <= 50000 && Zlength(l) == numsSize && IntArray::full(nums, numsSize, l)
    Ensure IsMajorityElement(__return, l) && IntArray::full(nums, numsSize, l)
*/
{
    int vote = 0;
    int candidate = 0;
    /*@ Inv Assert
        exists x l1 l2,
            nums == nums@pre && numsSize == numsSize@pre &&
            l == app(l1, l2) &&
            i == Zlength(l1) &&
            0 <= i && i <= numsSize &&
            1 <= numsSize && numsSize <= 50000 &&
            0 <= vote && vote <= i &&
            IsMajorityElement(x, l) &&
            MajorityOnReduced(x, candidate, vote, l2) &&
            IntArray::full(nums, numsSize, l)
    */
    for (int i = 0; i < numsSize; i++) {
        if (vote == 0) {
            candidate = nums[i];
        }
        vote += (nums[i] == candidate) ? 1 : -1;
    }
    return candidate;
}

